/**
 * Fix MongoDB URL update — replaces all remaining Cloudinary URLs with ImageKit URLs
 * using the migration-map.json generated by migrate-to-imagekit.js
 */

import 'dotenv/config';
import fs from 'fs';
import path from 'path';
import mongoose from 'mongoose';

const mapFile = path.join(process.cwd(), 'scripts', 'migration-map.json');
const urlMapping = JSON.parse(fs.readFileSync(mapFile, 'utf8'));

console.log(`Loaded ${Object.keys(urlMapping).length} URL mappings`);

await mongoose.connect(process.env.MONGO_URI);
console.log('Connected to MongoDB\n');

function mapUrl(url) {
  if (!url || typeof url !== 'string') return url;
  return urlMapping[url] || url;
}

function hasCloudinary(url) {
  return typeof url === 'string' && url.includes('res.cloudinary.com');
}

/** Walk any value deeply and replace Cloudinary URLs */
function deepReplace(value) {
  if (!value) return { value, changed: false };

  if (typeof value === 'string') {
    if (hasCloudinary(value)) {
      return { value: mapUrl(value), changed: true };
    }
    return { value, changed: false };
  }

  if (Array.isArray(value)) {
    let changed = false;
    const result = value.map(item => {
      const r = deepReplace(item);
      if (r.changed) changed = true;
      return r.value;
    });
    return { value: result, changed };
  }

  if (typeof value === 'object') {
    let changed = false;
    const result = {};
    for (const key of Object.keys(value)) {
      const r = deepReplace(value[key]);
      if (r.changed) changed = true;
      result[key] = r.value;
    }
    return { value: result, changed };
  }

  return { value, changed: false };
}

async function updateCollection(name) {
  const col = mongoose.connection.collection(name);
  const docs = await col.find({}).toArray();
  let updated = 0;

  for (const doc of docs) {
    const { _id, ...rest } = doc;
    const { value: newDoc, changed } = deepReplace(rest);
    if (changed) {
      await col.replaceOne({ _id }, { _id, ...newDoc });
      updated++;
    }
  }

  console.log(`  ${name}: updated ${updated} / ${docs.length} documents`);
}

console.log('Updating MongoDB collections...');
await updateCollection('products');
await updateCollection('reviews');
await updateCollection('orders');
await updateCollection('customdesigns');
await updateCollection('settings');
await updateCollection('categories');
await updateCollection('users');

console.log('\nDone! All Cloudinary URLs replaced with ImageKit URLs.');
await mongoose.disconnect();
